import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RatingDistribution {
  stars: number;
  count: number;
}

interface ProductRatingData {
  product: {
    name: string;
    averageRating: number;
    reviewCount: number;
  };
  ratingDistribution: RatingDistribution[];
}

export default function Widget() {
  const ratingData = response.data as ProductRatingData;
  const { product, ratingDistribution } = ratingData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FFB300' }}>
              {product.name}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#8E24AA' }}>
              {product.averageRating.toFixed(1)}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Based on {product.reviewCount.toLocaleString()} reviews
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: ratingDistribution.map(d => d.count),
                color: '#FFB300',
              },
            ]}
            xAxis={[
              {
                data: ratingDistribution.map(d => `${d.stars}★`),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
